+    /// before attempting a full refresh — so the row immediately reflects
+    /// success even if the post-refresh `fetchUserAgents()` fails for any
+    /// reason (network blip, server hiccup). Without this, a refresh failure
+    /// would leave the NEW pill + update icon visible despite a successful
+    /// redeploy, prompting the user to retry a no-op.
+    ///
+    /// Caller drives row-level loading via `loadingIds`. Returns `true` only
+    /// if the redeploy itself succeeded; refresh failure is logged but does
+    /// not fail the operation since the local state is already consistent.
+    @discardableResult
+    func updateAgent(id: String) async -> Bool {
+        do {
+            try await agentService.updateAgent(agentId: id)
+        } catch {
+            logger.error("updateAgent failed: \(error)")
+            AppError.capture(error, level: .warning, tags: ["flow": "agent", "step": "update", "agent_id": id])
+            return false
