+import SwiftUI
+
+struct AgentDetailSheet: View {
+    let item: AgentCatalogItem
+    let isHired: Bool
+    let hasUpdate: Bool
+    let onHire: () -> Void
+    let onFire: () -> Void
+    let onUpdate: () -> Void
+    let onChat: () -> Void
+    @Environment(\.dismiss) private var dismiss
+    @State private var showMoreActions = false
+    @State private var showFireConfirmation = false
+    /// Tracks whether the user tapped "Fire" inside `AgentMoreActionSheet`.
+    /// We can't surface `FireConfirmationDialog` until that sheet has fully
+    /// dismissed, so the intent is parked here and resolved in `onDismiss`.
+    @State private var pendingFireConfirmation = false
+
+    var body: some View {
+        ZStack(alignment: .bottom) {
+            ScrollView {
+                VStack(spacing: 0) {
+                    ViewHeaderBar(
+                        title: item.name,
+                        trailing: .icon("xmark"),
+                        onTrailingTap: { dismiss() }
