+
+                    // Avatar
+                    avatarView
+                        .frame(width: 96, height: 96)
+                        .clipShape(Circle())
+                        .padding(.top, 10)
+                        .padding(.bottom, 18)
+
+                    // Subtitle (only shown for official agents)
+                    if item.scope == "official" {
+                        Text("By ZooClaw official")
+                            .font(.custom("HankenGrotesk-Regular", size: 13).weight(.medium))
+                            .foregroundStyle(AppTheme.Agents.detailSheetSubtitleText)
+                            .padding(.bottom, 12)
+                    }
+
+                    // Description
+                    Text(item.description.isEmpty ? item.shortBio : item.description)
+                        .font(.custom("HankenGrotesk-Regular", size: 14).weight(.medium))
+                        .foregroundStyle(AppTheme.coolTextSecondary)
+                        .multilineTextAlignment(.center)
+                        .lineSpacing(4)
+                        .padding(.horizontal, 32)
+
+                    // Capabilities
+                    if !item.skills.isEmpty {
+                        capabilitiesSection
+                            .padding(.top, 24)
+                    }
+
+                    // Bottom spacing for the fixed button
+                    Spacer()
+                        .frame(height: 120)
+                }
+            }
+            .scrollIndicators(.hidden)
+
+            // Bottom gradient + hire button
+            bottomActionBar
+
+            // Stage 2: centered confirmation modal. Tapping its Fire
+            // button is the actual destructive action. Lives as an overlay
+            // (not a nested sheet) so it stays scoped to the parent's
+            // ZStack and can re-use the avatar from `item`.
+            if showFireConfirmation {
+                FireConfirmationDialog(
+                    agentName: item.name,
+                    avatarURL: item.avatarURL,
+                    emoji: item.emoji,
+                    isPresented: $showFireConfirmation,
+                    onConfirm: {
+                        onFire()
+                        dismiss()
+                    }
+                )
+                .transition(.opacity)
+            }
+        }
+        .background(Color.white)
+        .presentationCornerRadius(32)
+        .presentationDragIndicator(.visible)
+        .animation(.easeInOut(duration: 0.2), value: showFireConfirmation)
+        // Stage 1: bottom action sheet (Fire / Cancel) triggered by the
+        // ellipsis. Native sheet supplies slide-up animation, drag indicator,
+        // and swipe-to-dismiss. The follow-up confirmation modal is queued
+        // in `onDismiss` so it doesn't race the sheet's retraction animation.
+        .sheet(
+            isPresented: $showMoreActions,
+            onDismiss: {
+                if pendingFireConfirmation {
+                    pendingFireConfirmation = false
+                    showFireConfirmation = true
+                }
+            },
+            content: {
+                AgentMoreActionSheet(onFire: {
+                    pendingFireConfirmation = true
+                })
+                .presentationDetents([.height(160)])
+                .presentationCornerRadius(32)
+                .presentationBackground(Color.white)
+            }
+        )
+    }
+
