+import SwiftUI
+
+struct AgentsView: View {
+    @Environment(AgentViewModel.self) private var agentViewModel
+    @Environment(AuthViewModel.self) private var authViewModel
+    var onMenuTap: (() -> Void)?
+    var onChatNow: ((AgentCatalogItem) -> Void)?
+    var onAgentHired: ((AgentCatalogItem) -> Void)?
+    var onAgentFired: ((AgentCatalogItem) -> Void)?
+
+    @State private var loadingIds: Set<String> = []
+    @State private var errorMessage: String?
+
+    private var hiredAgentIds: Set<String> {
+        Set(agentViewModel.userAgents.map(\.id))
+    }
+
+    private var updatableAgentIds: Set<String> {
+        Set(agentViewModel.userAgents.filter(\.hasUpdate).map(\.id))
+    }
+
+    var body: some View {
+        ZStack(alignment: .top) {
+            LinearGradient(
+                colors: [AppTheme.Agents.bgGradientTop, AppTheme.Agents.bgGradientBottom],
+                startPoint: .top,
+                endPoint: .bottom
+            )
+            .ignoresSafeArea()
+
+            VStack(spacing: 0) {
+                headerBar
+                    .padding(.top, 12)
+                    .padding(.bottom, 16)
+
+                categoryTabs
+                    .padding(.bottom, 16)
+
+                List {
+                    ForEach(agentViewModel.filteredCatalog, id: \.id) { item in
+                        AgentRowView(
+                            item: item,
+                            isHired: hiredAgentIds.contains(item.id),
+                            isLoading: loadingIds.contains(item.id),
+                            hasUpdate: updatableAgentIds.contains(item.id),
+                            onAction: { handleAction(item) },
+                            onChat: { onChatNow?(item) },
+                            onUpdate: { handleUpdate(item) }
+                        )
+                        .listRowSeparator(.hidden)
+                        .listRowBackground(Color.clear)
+                        .listRowInsets(EdgeInsets(top: 6, leading: 20, bottom: 6, trailing: 20))
+                    }
+                }
+                .listStyle(.plain)
+                .scrollContentBackground(.hidden)
+                .contentMargins(.top, 8, for: .scrollContent)
+                .contentMargins(.bottom, 32, for: .scrollContent)
+            }
+
+            if let msg = errorMessage {
+                VStack {
+                    Spacer()
+                    Text(msg)
+                        .font(.system(size: 14))
+                        .foregroundStyle(.white)
+                        .padding(.horizontal, 16)
+                        .padding(.vertical, 10)
+                        .background(AppTheme.Agents.toastBg)
+                        .clipShape(RoundedRectangle(cornerRadius: 10))
+                        .padding(.bottom, 40)
+                }
+                .transition(.move(edge: .bottom).combined(with: .opacity))
+                .onAppear {
+                    DispatchQueue.main.asyncAfter(deadline: .now() + 3) {
+                        withAnimation { errorMessage = nil }
+                    }
+                }
+            }
+        }
+        .animation(.easeInOut(duration: 0.2), value: errorMessage != nil)
+    }
+
+    // MARK: - Header
+
+    private var headerBar: some View {
+        ViewHeaderBar(
+            title: "AI Specialists Hub",
+            leading: .icon("line.3.horizontal"),
+            leadingLiquidGlass: true,
+            onLeadingTap: { onMenuTap?() }
+        )
+    }
+
+    // MARK: - Category Tabs
+
+    private var categoryTabs: some View {
+        @Bindable var vm = agentViewModel
+        return ScrollView(.horizontal, showsIndicators: false) {
+            HStack(spacing: 8) {
+                categoryPill(label: "All", isActive: vm.selectedCategory == nil) {
+                    vm.selectedCategory = nil
+                }
+                ForEach(vm.availableCategories, id: \.self) { category in
+                    let isActive = vm.selectedCategory?.lowercased() == category.lowercased()
+                    categoryPill(label: category.localizedCapitalized, isActive: isActive) {
+                        vm.selectedCategory = category
+                    }
+                }
+            }
+            .padding(.horizontal, 20)
+        }
+    }
+
+    private func categoryPill(
+        label: String,
+        isActive: Bool,
+        action: @escaping () -> Void
+    ) -> some View {
+        Button(action: action) {
+            Text(label)
+                .font(.custom("HankenGrotesk-Medium", size: 13).weight(.medium))
+                .foregroundStyle(isActive ? .white : AppTheme.coolTextSecondary)
+                .padding(.horizontal, 14)
+                .padding(.vertical, 8)
+                .background(isActive ? AppTheme.deepNavy : AppTheme.bgPage)
+                .clipShape(Capsule())
+                .overlay(
+                    Capsule()
+                        .stroke(
+                            isActive ? Color.clear : AppTheme.coolBorderLight,
+                            lineWidth: 1
+                        )
+                )
+        }
+        .buttonStyle(.plain)
+    }
+
+    // MARK: - Actions
+
+    private func handleAction(_ item: AgentCatalogItem) {
+        guard !loadingIds.contains(item.id) else { return }
+        let isHired = hiredAgentIds.contains(item.id)
+        loadingIds.insert(item.id)
+        Task {
+            if isHired {
+                let succeeded = await agentViewModel.fireAgent(id: item.id)
+                await authViewModel.refreshUserAccount()
+                if succeeded {
+                    onAgentFired?(item)
+                } else {
+                    errorMessage = "Couldn't remove \(item.name). Please try again."
+                }
+            } else {
+                let succeeded = await agentViewModel.hireAgent(id: item.id)
+                await authViewModel.refreshUserAccount()
+                if succeeded {
+                    onAgentHired?(item)
+                } else {
+                    errorMessage = "Couldn't hire \(item.name). Please try again."
+                }
+            }
+            loadingIds.remove(item.id)
+        }
+    }
+
+    private func handleUpdate(_ item: AgentCatalogItem) {
+        guard !loadingIds.contains(item.id) else { return }
+        loadingIds.insert(item.id)
+        Task {
+            let succeeded = await agentViewModel.updateAgent(id: item.id)
+            if !succeeded {
+                errorMessage = "Couldn't update \(item.name). Please try again."
+            }
+            loadingIds.remove(item.id)
+        }
+    }
+
+}
+
