+import SwiftUI
+
+/// Centered modal dialog used to confirm firing an agent.
+///
+/// Rendered as an overlay (backdrop + card) inside the parent sheet's ZStack
+/// rather than via `.confirmationDialog`, so layout is deterministic inside
+/// the sheet's presentation hierarchy and the avatar can overlap the card top.
+struct FireConfirmationDialog: View {
+    let agentName: String
+    let avatarURL: String
+    let emoji: String
+    @Binding var isPresented: Bool
+    let onConfirm: () -> Void
+
+    var body: some View {
+        ZStack {
+            backdrop
+            card
+        }
+    }
+
+    // MARK: - Subviews
+
+    private var backdrop: some View {
+        Color.black.opacity(0.45)
+            .ignoresSafeArea()
+            .contentShape(Rectangle())
+            .onTapGesture { isPresented = false }
+    }
+
+    private var card: some View {
+        VStack(spacing: 8) {
+            Text("Fire \(agentName)?")
+                .font(.custom("HankenGrotesk-Bold", size: 17).weight(.bold))
+                .foregroundStyle(AppTheme.deepNavy)
+
+            Text("Deletes all chats, memories & workspace data.")
+                .font(.custom("HankenGrotesk-Regular", size: 14))
+                .foregroundStyle(AppTheme.coolTextSecondary)
+                .multilineTextAlignment(.center)
+                .padding(.horizontal, 4)
+
+            HStack(spacing: 12) {
+                cancelButton
+                fireButton
+            }
+            .padding(.top, 8)
+        }
+        .padding(.horizontal, 14)
+        // Avatar overlay (64pt) sits half-above / half-inside the card,
+        // consuming 32pt of card top. Spec shows a 20pt visible gap below
+        // the avatar before the title, so total top padding = 32 + 20.
+        .padding(.top, 52)
+        .padding(.bottom, 20)
+        .frame(maxWidth: .infinity)
+        .background(Color.white)
+        .clipShape(RoundedRectangle(cornerRadius: 20))
+        .overlay(alignment: .top) { avatarBadge }
+        .padding(.horizontal, 32)
+    }
+
+    private var cancelButton: some View {
+        Button {
+            isPresented = false
+        } label: {
+            Text("Cancel")
+                .font(.system(size: 16, weight: .semibold))
+                .foregroundStyle(AppTheme.textPrimary)
+                .frame(maxWidth: .infinity)
+                .padding(.vertical, 14)
+                .background(AppTheme.bgPage)
+                .clipShape(Capsule())
+        }
+        .buttonStyle(.plain)
+    }
+
+    private var fireButton: some View {
+        Button {
+            isPresented = false
+            onConfirm()
+        } label: {
+            Text("Fire")
+                .font(.system(size: 16, weight: .semibold))
+                .foregroundStyle(.white)
+                .frame(maxWidth: .infinity)
+                .padding(.vertical, 14)
+                .background(AppTheme.dangerBright)
+                .clipShape(Capsule())
+        }
+        .buttonStyle(.plain)
+    }
+
+    private var avatarBadge: some View {
+        avatarContent
+            .frame(width: 64, height: 64)
+            .clipShape(Circle())
+            .overlay(Circle().stroke(Color.white, lineWidth: 4))
+            .offset(y: -32)
+    }
+
+    @ViewBuilder
+    private var avatarContent: some View {
+        if let url = URL(string: avatarURL), !avatarURL.isEmpty {
+            CachedAsyncImage(url: url) {
+                Text(emoji).font(.system(size: 28))
+            }
+        } else {
+            Text(emoji)
+                .font(.system(size: 28))
+                .frame(maxWidth: .infinity, maxHeight: .infinity)
+                .background(AppTheme.bgInput)
+        }
+    }
+}

