+    /// Submit an async install operation. Returns immediately with an
+    /// `operationId` the caller can poll via `agentOperation(operationId:)`.
+    /// Pass `source: "official"` for catalog agents, `"custom"` for user uploads.
+    /// Hits the `/install/async` route — the bare `/install` route is the
+    /// blocking variant and returns `{ok, agent_id}` (no `operation_id`).
+    func installAgent(agentId: String, source: String = "official") async throws -> String {
+        struct Body: Encodable, Sendable {
+            let agent_id: String
+            let source: String
+        }
+        let response: AgentOperationCreateResponse = try await networkService.request(
+            endpoint: "openclaw/agents/install/async",
+            method: .post,
+            body: Body(agent_id: agentId, source: source)
+        )
+        return response.operationId
+    }
+
+    /// Poll status of a previously-submitted install/uninstall operation.
+    func agentOperation(operationId: String) async throws -> AgentOperation {
+        try await networkService.request(
+            endpoint: "openclaw/agents/operations/\(operationId)"
+        )
+    }
